const items = $input.all();
let report = `# CVETriage Report\n`;
report += `**Generated:** ${new Date().toISOString()}\n\n`;
report += `---\n\n`;

for (const item of items) {
  let parsed;
  try {
    const raw = item.json.output.replace(/```json|```/g, '').trim();
    parsed = JSON.parse(raw);
  } catch(e) {
    continue;
  }

  report += `## ${parsed.service} — ${parsed.ip}:${parsed.port}\n\n`;
  report += `| CVE ID | CVSS | Priority | Summary |\n`;
  report += `|--------|------|----------|---------|\n`;

  for (const cve of parsed.cves) {
    report += `| ${cve.id} | ${cve.cvss} | ${cve.priority} | ${cve.summary} |\n`;
  }

  report += `\n### Remediation Steps\n`;
  for (const cve of parsed.cves) {
    report += `- **${cve.id}:** ${cve.remediation}\n`;
  }
  report += `\n---\n\n`;
}

return [{ json: { report, generatedAt: new Date().toISOString() } }];

const report = $input.first().json.report;
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const filename = `cvetriage_report_${timestamp}.md`;

const binary = Buffer.from(report.replace(/\\n/g, '\n'), 'utf8').toString('base64');

return [{
  json: {
    filename,
    generatedAt: $input.first().json.generatedAt
  },
  binary: {
    data: {
      data: binary,
      mimeType: 'text/markdown',
      fileName: filename
    }
  }
}];
